304→        return () => {
305→            cancelled = true;
306→        };
307→    }, [userId]);
308→
309→    // One-time wormhole fetch on mount
310→    useEffect(() => {
311→        let cancelled = false;
312→
313→        const fetchWormholes = async () => {
