328→                }
329→            } catch (err) {
330→                if (!cancelled) {
331→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
332→                }
333→            }
334→        };
335→
336→        fetchWormholes();
337→        return () => { cancelled = true; };
338→    }, []);
339→
340→    // Debounced fetch on camera/zoom change
341→    useEffect(() => {
342→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
343→
344→        fetchDebounceRef.current = setTimeout(async () => {
345→            const bounds = getViewportBounds();
346→            try {
347→                const result = await getUniversePosts(
348→                    bounds.minX,
349→                    bounds.maxX,
350→                    bounds.minY,
351→                    bounds.maxY,
