368→                }
369→                // Keep server gravity data as fallback when embeddings are absent in payload.
370→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
371→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
372→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
373→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
374→
375→                // Fetch constellations for visible posts
