496→
497→    // One-time auto focus after first payload is loaded.
498→    // Skip if we have a constellation flyTo target — that effect handles it instead.
499→    useEffect(() => {
500→        if (!userId) return;
501→        if (isInitialLoading) return;
502→        if (hasAutoFocusedOwnGalaxyRef.current) return;
503→        if (constellationFlyToRef.current) return;
504→
505→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
506→        const target = ownGalaxy
507→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
508→            : (centroidTargets.get(userId) || ownGalaxyTarget);
509→
510→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
511→        if (!target) return;
512→
513→        hasAutoFocusedOwnGalaxyRef.current = true;
514→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
515→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
516→
517→    // Fly to constellation midpoint when arriving from a notification link.
518→    useEffect(() => {
519→        const target = constellationFlyToRef.current;
520→        if (!target) return;
521→        if (isInitialLoading) return;
522→
523→        const posA = finalStarPositions.get(target.starIdA);
524→        const posB = finalStarPositions.get(target.starIdB);
525→        if (!posA || !posB) return;
526→
527→        constellationFlyToRef.current = null;
528→        hasAutoFocusedOwnGalaxyRef.current = true;
529→
530→        const mx = (posA.x + posB.x) / 2;
531→        const my = (posA.y + posB.y) / 2;
532→        flyTo(mx, my, 1.0);
533→
534→        // Clear navigation state so refreshing doesn't re-trigger
535→        navigate(location.pathname, { replace: true, state: {} });
536→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
537→
538→    const settledPayload = useMemo(() => {
539→        if (!isSettled || activePosts.length === 0) return [];
540→
541→        const payload = [];
542→        for (const post of activePosts) {
543→            if (!post?.id) continue;
544→            const pos = getComputedStarPosition(post);
545→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
546→
547→            payload.push({
548→                post_id: post.id,
549→                settled_x: Math.round(pos.x * 100) / 100,
550→                settled_y: Math.round(pos.y * 100) / 100,
551→            });
552→        }
553→
554→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
555→        return payload;
556→    }, [activePosts, getComputedStarPosition, isSettled]);
557→
558→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
559→    useEffect(() => {
560→        if (!ENABLE_SETTLED_RPC_SAVE) return;
561→        if (!isSettled || settledPayload.length === 0) return;
562→
563→        const signature = JSON.stringify(settledPayload);
564→        if (signature === lastSettledPayloadRef.current) return;
565→
566→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
567→        settleDebounceRef.current = setTimeout(async () => {
568→            lastSettledPayloadRef.current = signature;
569→            try {
570→                const { error } = await supabase.rpc('save_universe_settled_positions', {
571→                    positions_payload: settledPayload,
572→                });
573→                if (error) {
574→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
575→                }
576→            } catch (err) {
577→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
578→            }
579→        }, 1200);
580→
581→        return () => {
582→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
583→        };
584→    }, [isSettled, settledPayload]);
585→
586→    // ESC key to cancel link mode
587→    useEffect(() => {
588→        if (!isLinkMode) return;
589→        const handleKeyDown = (e) => {
590→            if (e.key === 'Escape') cancelLinkMode();
591→        };
592→        window.addEventListener('keydown', handleKeyDown);
593→        return () => window.removeEventListener('keydown', handleKeyDown);
594→    }, [isLinkMode, cancelLinkMode]);
595→
596→    useEffect(() => {
597→        return () => {
598→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
599→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
600→        };
601→    }, []);
602→
603→    return (
604→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
605→            <button className={styles.backButton} onClick={() => navigate('/home')}>
606→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
607→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
608→                </svg>
609→                Back
610→            </button>
611→
612→            {userId && (
613→                <button
614→                    className={`${styles.linkModeButton} ${isLinkMode ? styles.linkModeActive : ''}`}
615→                    onClick={toggleLinkMode}
616→                    disabled={isSubmitting}
617→                >
618→                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
619→                        <path d="M3.9 12c0-1.71 1.39-3.1 3.1-3.1h4V7H7c-2.76 0-5 2.24-5 5s2.24 5 5 5h4v-1.9H7c-1.71 0-3.1-1.39-3.1-3.1zM8 13h8v-2H8v2zm9-6h-4v1.9h4c1.71 0 3.1 1.39 3.1 3.1s-1.39 3.1-3.1 3.1h-4V17h4c2.76 0 5-2.24 5-5s-2.24-5-5-5z"/>
620→                    </svg>
621→                    {isLinkMode
622→                        ? (secondStar ? 'Naming link...' : (firstStar ? 'Select second star...' : 'Select your star...'))
623→                        : 'Link Stars'}
624→                </button>
625→            )}
626→
627→            {isLinkMode && linkModeStatus === 'enter_label' && (
628→                <div className={styles.labelInputPanel}>
629→                    <div className={styles.labelInputHeader}>
630→                        Link "{firstStar?.title}" ↔ "{secondStar?.title}"
631→                    </div>
632→                    <input
633→                        className={styles.labelInputField}
634→                        type="text"
635→                        placeholder="Name this constellation (optional)"
636→                        value={labelInput}
637→                        onChange={(e) => setLabelInput(e.target.value)}
638→                        onKeyDown={(e) => {
