640→                                submitLink(labelInput);
641→                                setLabelInput('');
642→                            }
643→                        }}
644→                        autoFocus
645→                    />
646→                    <div className={styles.labelInputActions}>
647→                        <button
648→                            className={styles.labelInputCreate}
649→                            disabled={isSubmitting}
650→                            onClick={() => {
651→                                submitLink(labelInput);
652→                                setLabelInput('');
653→                            }}
654→                        >
655→                            {isSubmitting ? 'Creating...' : 'Create Link'}
656→                        </button>
657→                        <button
658→                            className={styles.labelInputCancel}
659→                            onClick={() => {
660→                                cancelLinkMode();
661→                                setLabelInput('');
662→                            }}
663→                        >
664→                            Cancel
665→                        </button>
666→                    </div>
667→                </div>
