819→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
820→                    <div className={styles.previewLikes}>
821→                        {(() => {
822→                            const count = selectedPost.like_count != null
823→                                ? selectedPost.like_count
824→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
825→                                    ? selectedPost.likes[0].count : 0);
826→                            return `${count} like${count !== 1 ? 's' : ''}`;
827→                        })()}
828→                    </div>
829→                    <div className={styles.previewActions}>
830→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
831→                            Read
