  1→import React, { useMemo } from 'react';
  2→import { Layer, Group, Text, Shape } from 'react-konva';
  3→import StarGroup from '../components/StarGroup';
  4→import { getStarColor, getStarRadius, userHomeCoords } from '../utils/starUtils';
  5→import { generateGalaxyData, drawGalaxyVisuals } from '../utils/galaxyVisuals';
  6→import { computeSemanticBridges } from '../utils/cosmicPhysics';
  7→
  8→const GalaxyLabel = React.memo(({ x, y, name, zoom, onClick }) => {
  9→    const invZoom = 1 / zoom;
 10→    return (
 11→        <Group x={x} y={y} scaleX={invZoom} scaleY={invZoom}>
 12→            <Text
 13→                text={name}
 14→                fontSize={14}
 15→                fill="rgba(255,255,255,0.45)"
 16→                fontStyle="600"
 17→                fontFamily="inherit"
 18→                align="center"
 19→                width={200}
 20→                offsetX={100}
 21→                y={-24}
 22→                perfectDrawEnabled={false}
 23→                onMouseEnter={(e) => {
 24→                    e.target.fill('rgba(255,255,255,0.75)');
 25→                    const container = e.target.getStage().container();
 26→                    container.style.cursor = 'pointer';
 27→                }}
 28→                onMouseLeave={(e) => {
 29→                    e.target.fill('rgba(255,255,255,0.45)');
 30→                    const container = e.target.getStage().container();
 31→                    container.style.cursor = 'grab';
 32→                }}
 33→                onClick={onClick}
 34→                onTap={onClick}
 35→            />
 36→        </Group>
 37→    );
 38→});
 39→
 40→GalaxyLabel.displayName = 'GalaxyLabel';
 41→
 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges,
 47→    camera, stageSize,
 48→    computedStarPositions: computedStarPositionsProp,
 49→}) => {
 50→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 51→    const galaxyUserIdMap = useMemo(() => {
 52→        const map = new Map();
 53→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 54→        return map;
 55→    }, [galaxies]);
 56→
 57→    // Galaxy spiral visuals — positioned at animated galaxy coords
 58→    const galaxyVisuals = useMemo(() =>
 59→        galaxies?.map(g => ({
 60→            x: g.x,
 61→            y: g.y,
 62→            ...generateGalaxyData(g.userId),
 63→            color: getStarColor(g.userId),
 64→        })) || []
 65→    , [galaxies]);
 66→
 67→    // ── Compute every star's render position ─────────────────────────
 68→    // Use prop if provided (hoisted from Universe.jsx), otherwise compute locally.
 69→    const computedStarPositionsLocal = useMemo(() => {
 70→        if (computedStarPositionsProp) return computedStarPositionsProp;
 71→        const map = new Map();
 72→        for (const post of posts) {
 73→            const uid = post.users?.id ?? post.user_id;
 74→
 75→            const hashGal = userHomeCoords(uid);
 76→            const animGal = galaxyPositions?.get(uid);
 77→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 78→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 79→
 80→            const pull = starPullOffsets?.get(post.id);
 81→
 82→            const baseX = post.universe_x ?? post.display_x;
 83→            const baseY = post.universe_y ?? post.display_y;
 84→
 85→            map.set(post.id, {
 86→                x: baseX + galDx + (pull?.dx ?? 0),
 87→                y: baseY + galDy + (pull?.dy ?? 0),
 88→            });
 89→        }
 90→        return map;
 91→    }, [computedStarPositionsProp, posts, galaxyPositions, starPullOffsets]);
 92→    const computedStarPositions = computedStarPositionsLocal;
 93→
 94→    // ── Viewport culling: only render stars within visible bounds + buffer ──
 95→    const visibleBounds = useMemo(() => {
 96→        if (!camera || !stageSize || !zoom) return null;
 97→        const halfW = (stageSize.width / 2) / zoom;
 98→        const halfH = (stageSize.height / 2) / zoom;
 99→        const bufferWorld = 500 / zoom;
100→        return {
101→            minX: camera.x - halfW - bufferWorld,
102→            maxX: camera.x + halfW + bufferWorld,
103→            minY: camera.y - halfH - bufferWorld,
104→            maxY: camera.y + halfH + bufferWorld,
105→        };
106→    }, [camera, stageSize, zoom]);
107→
108→    const visiblePosts = useMemo(() => {
109→        if (!visibleBounds) return posts; // fallback: render all
110→        return posts.filter(post => {
111→            const pos = computedStarPositions.get(post.id);
112→            if (!pos) return true; // keep if no position computed yet
113→            return pos.x >= visibleBounds.minX && pos.x <= visibleBounds.maxX
114→                && pos.y >= visibleBounds.minY && pos.y <= visibleBounds.maxY;
115→        });
116→    }, [posts, computedStarPositions, visibleBounds]);
117→
118→    const bridgePairs = useMemo(() => {
119→        const maxPairs = 120;
120→
121→        if (useEmbeddingBridges) {
122→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
123→                ? posts.filter((post) => activePostIds.has(post?.id))
124→                : posts;
125→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
126→        }
127→
128→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
129→
130→        return similarPairs
131→            .filter((pair) => Number(pair?.similarity) > 0.9)
132→            .filter((pair) => {
133→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
134→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
135→            })
136→            .slice(0, maxPairs);
137→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
138→
139→    return (
140→        <Layer {...layerProps}>
141→            {/* Semantic bridges between similar posts */}
142→            {bridgePairs.length > 0 && (
143→                <Shape
144→                    sceneFunc={(ctx) => {
145→                        for (const pair of bridgePairs) {
146→                            const posA = computedStarPositions.get(pair.post_a);
147→                            const posB = computedStarPositions.get(pair.post_b);
148→                            if (!posA || !posB) continue;
149→
150→                            const dx = posB.x - posA.x;
151→                            const dy = posB.y - posA.y;
152→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
153→
154→                            const mx = (posA.x + posB.x) / 2;
155→                            const my = (posA.y + posB.y) / 2;
156→                            const perpX = (-dy / dist) * dist * 0.06;
157→                            const perpY = (dx / dist) * dist * 0.06;
158→
159→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
160→                            ctx.lineWidth = 0.8;
161→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
162→                            ctx.shadowBlur = 4;
163→                            ctx.beginPath();
164→                            ctx.moveTo(posA.x, posA.y);
165→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
166→                            ctx.stroke();
167→                        }
168→                        ctx.shadowBlur = 0;
169→                    }}
170→                    perfectDrawEnabled={false}
171→                    listening={false}
172→                />
173→            )}
174→            {/* Spiral galaxy visuals + connection lines */}
175→            <Shape
176→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
177→                perfectDrawEnabled={false}
178→                listening={false}
179→            />
180→            {/* Galaxy name labels */}
181→            {galaxies?.map((g) => (
182→                <GalaxyLabel
183→                    key={g.userId}
184→                    x={g.x}
185→                    y={g.y}
186→                    name={g.name}
187→                    zoom={zoom}
188→                    onClick={() => onGalaxyClick(g)}
189→                />
190→            ))}
191→            {/* Stars (viewport-culled) */}
192→            {visiblePosts.map((post) => {
193→                const postUserId = post.users?.id ?? post.user_id;
194→                const color = getStarColor(postUserId);
195→                const likeCount = post.like_count != null
196→                    ? post.like_count
197→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
198→                const radius = getStarRadius(likeCount);
199→
200→                const pos = computedStarPositions.get(post.id);
201→                const x = pos?.x ?? post.universe_x ?? post.display_x;
202→                const y = pos?.y ?? post.universe_y ?? post.display_y;
203→
204→                return (
205→                    <StarGroup
206→                        key={post.id}
207→                        x={x}
208→                        y={y}
209→                        radius={radius}
210→                        color={color}
