.galaxyPreviewBg {
    height: 120px;
    border-radius: 16px 16px 0 0;
    background-size: cover;
    background-position: center;
    background-color: rgba(95, 146, 255, 0.12);
}

.galaxyPreviewContent {
    padding: 0 20px 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.galaxyPreviewAvatar {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid rgba(255, 255, 255, 0.15);
    margin-top: -28px;
    background: #0a0e1a;
}

.galaxyPreviewHeading {
    font-size: 15px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
    margin-top: 10px;
    text-align: center;
}

.galaxyPreviewBio {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.5);
    margin-top: 8px;
    text-align: center;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.galaxyPreviewVisitBtn {
    display: inline-block;
    margin-top: 16px;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewVisitBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

/* Minimap */
.minimap {
    position: absolute;
    bottom: 16px;
    left: 16px;
    z-index: 1010;
    width: 160px;
    height: 160px;
    border-radius: 10px;
    cursor: crosshair;
    pointer-events: auto;
    transition: opacity 0.2s;
}

.minimap:hover {
    opacity: 0.95;
}

/* Link Mode UI */
.linkModeButton {
    position: absolute;
    top: 16px;
    left: 130px;
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 13px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s, box-shadow 0.2s;
}

.linkModeButton:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.linkModeButton svg {
    flex-shrink: 0;
}

.linkModeActive {
    background: rgba(95, 146, 255, 0.12);
    border-color: rgba(95, 146, 255, 0.5);
    color: #5f92ff;
    box-shadow: 0 0 16px rgba(95, 146, 255, 0.2), inset 0 0 8px rgba(95, 146, 255, 0.08);
}

.linkModeActive:hover {
    background: rgba(95, 146, 255, 0.18);
    border-color: rgba(95, 146, 255, 0.6);
}

.linkModeIndicator {
    position: absolute;
    top: 66px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 20px;
    background: rgba(10, 14, 26, 0.85);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(95, 146, 255, 0.3);
    border-radius: 12px;
    color: rgba(255, 255, 255, 0.8);
    font-size: 13px;
    white-space: nowrap;
}

.linkModeCancel {
    padding: 4px 12px;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.15);
    border-radius: 8px;
    color: rgba(255, 255, 255, 0.6);
    font-size: 12px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
}

.linkModeCancel:hover {
    background: rgba(255, 255, 255, 0.15);
    color: #fff;
}

/* Label input panel for constellation naming */
.labelInputPanel {
    position: absolute;
    top: 66px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1010;
    display: flex;
    flex-direction: column;
    gap: 10px;
    padding: 16px 20px;
    background: rgba(10, 14, 26, 0.88);
    backdrop-filter: blur(14px);
    -webkit-backdrop-filter: blur(14px);
    border: 1px solid rgba(95, 146, 255, 0.3);
    border-radius: 14px;
    min-width: 280px;
    max-width: 380px;
}

.labelInputHeader {
    font-size: 13px;
    color: rgba(255, 255, 255, 0.75);
    text-align: center;
    line-height: 1.4;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.labelInputField {
    width: 100%;
    padding: 8px 0;
    background: transparent;
    border: none;
    border-bottom: 1px solid rgba(255, 255, 255, 0.15);
    color: #fff;
    font-size: 14px;
    font-family: inherit;
    outline: none;
    transition: border-color 0.2s;
    box-sizing: border-box;
}

.labelInputField::placeholder {
    color: rgba(255, 255, 255, 0.3);
}

.labelInputField:focus {
    border-bottom-color: rgba(95, 146, 255, 0.5);
}

.labelInputActions {
    display: flex;
    gap: 8px;
    justify-content: flex-end;
}

.labelInputCreate {
    padding: 7px 18px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.labelInputCreate:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

.labelInputCreate:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.labelInputCancel {
    padding: 7px 14px;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 10px;
    color: rgba(255, 255, 255, 0.5);
    font-size: 13px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
}

.labelInputCancel:hover {
    background: rgba(255, 255, 255, 0.12);
    color: rgba(255, 255, 255, 0.8);
}

/* Wormhole warp overlay */
.warpOverlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        transparent 20%,
        rgba(95, 146, 255, 0.15) 60%,
        rgba(0, 0, 0, 0.6) 100%
    );
    animation: warpPulse 1.8s ease-in-out forwards;
}

@keyframes warpPulse {
    0%   { opacity: 0; }
    15%  { opacity: 1; }
    85%  { opacity: 1; }
    100% { opacity: 0; }
}

@media (max-width: 600px) {
    .previewPanel {
        width: auto;
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
        box-sizing: border-box;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .distanceTracker {
        bottom: auto;
        top: 12px;
        right: 12px;
        left: auto;
    }

    .minimap {
        width: 100px;
        height: 100px;
        bottom: 12px;
        left: 12px;
    }

    .galaxyPreviewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 300px;
    }

    .linkModeButton {
        top: 12px;
        left: auto;
        right: 12px;
        padding: 8px 14px;
        font-size: 12px;
    }

    .linkModeIndicator {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        white-space: normal;
        font-size: 12px;
    }

    .labelInputPanel {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        min-width: 0;
        max-width: none;
    }

    .labelInputHeader {
        white-space: normal;
        font-size: 12px;
    }
}

