                            ctx.lineWidth = 0.8;
                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
                            ctx.shadowBlur = 4;
                            ctx.beginPath();
                            ctx.moveTo(posA.x, posA.y);
                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
                            ctx.stroke();
                        }
                        ctx.shadowBlur = 0;
                    }}
                    perfectDrawEnabled={false}
                    listening={false}
                />
            )}
            {/* Spiral galaxy visuals + connection lines */}
            <Shape
                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
                perfectDrawEnabled={false}
                listening={false}
            />
            {/* Galaxy name labels */}
            {galaxies?.map((g) => (
                <GalaxyLabel
                    key={g.userId}
                    x={g.x}
                    y={g.y}
                    name={g.name}
                    zoom={zoom}
                    onClick={() => onGalaxyClick(g)}
                />
            ))}
            {/* Stars (viewport-culled) */}
            {visiblePosts.map((post) => {
                const postUserId = post.users?.id ?? post.user_id;
                const color = getStarColor(postUserId);
                const likeCount = post.like_count != null
                    ? post.like_count
                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
                const radius = getStarRadius(likeCount);

                const pos = computedStarPositions.get(post.id);
                const x = pos?.x ?? post.universe_x ?? post.display_x;
                const y = pos?.y ?? post.universe_y ?? post.display_y;

                return (
                    <StarGroup
                        key={post.id}
                        x={x}
                        y={y}
                        radius={radius}
                        color={color}
                        title={post.title}
                        showTitle={showTitles}
                        isPulsing={pulsingId === post.id}
                        onClick={() => onStarClick(post)}
                    />
                );
            })}
        </Layer>
    );
});

