193→            {visiblePosts.map((post) => {
194→                const postUserId = post.users?.id ?? post.user_id;
195→                const color = getStarColor(postUserId);
196→                const likeCount = post.like_count != null
197→                    ? post.like_count
198→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
199→                const radius = getStarRadius(likeCount);
