201→                const pos = computedStarPositions.get(post.id);
202→                const x = pos?.x ?? post.universe_x ?? post.display_x;
203→                const y = pos?.y ?? post.universe_y ?? post.display_y;
204→
205→                const constellationColor = constellationStarColors?.get(post.id) || null;
206→
207→                return (
208→                    <StarGroup
209→                        key={post.id}
210→                        x={x}
211→                        y={y}
212→                        radius={radius}
213→                        color={color}
214→                        title={post.title}
215→                        showTitle={showTitles}
216→                        isPulsing={pulsingId === post.id}
217→                        onClick={() => onStarClick(post)}
218→                        constellationColor={constellationColor}
219→                    />
220→                );
221→            })}
222→        </Layer>
223→    );
224→});
225→
226→InteractiveLayer.displayName = 'InteractiveLayer';
227→
228→export default InteractiveLayer;
