572→
573→        const mx = (posA.x + posB.x) / 2;
574→        const my = (posA.y + posB.y) / 2;
575→        flyTo(mx, my, 1.0);
576→
577→        // Clear navigation state so refreshing doesn't re-trigger
578→        navigate(location.pathname, { replace: true, state: {} });
