581→    const settledPayload = useMemo(() => {
582→        if (!isSettled || activePosts.length === 0) return [];
583→
584→        const payload = [];
585→        for (const post of activePosts) {
586→            if (!post?.id) continue;
587→            const pos = getComputedStarPosition(post);
588→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
589→
590→            payload.push({
